    @Test
    fun testErrorHandlingInvalidSyntax() = runBlocking {
        // Parsing invalid syntax should produce a tree with error nodes.
        val config = MAPPER.readValue("{\"language\":\"javascript\"}", ProcessConfig::class.java)
        val result = TreeSitterLanguagePack.process("function function function @@@ %%%", config)
    }

    @Test
    fun testErrorHandlingUnknownLanguage() = runBlocking {
        // Loading a nonexistent language should produce an error.
        assertFailsWith<Exception> {
            val config = MAPPER.readValue("{\"language\":\"nonexistent_xyz\"}", ProcessConfig::class.java)
            TreeSitterLanguagePack.process("", config)
        }
        Unit
    }

    @Test
    fun testErrorProcessEmptySource() = runBlocking {
        // Process empty source code succeeds with zero metrics
        val config = MAPPER.readValue("{\"language\":\"python\"}", ProcessConfig::class.java)
        val result = TreeSitterLanguagePack.process("", config)
        assertEquals(0, result.metrics.totalLines)
    }

    @Test
    fun testParseEmptyLanguage() = runBlocking {
        // process() returns error with empty language name
        assertFailsWith<Exception> {
            val config = MAPPER.readValue("{\"language\":\"\"}", ProcessConfig::class.java)
            TreeSitterLanguagePack.process("x = 1", config)
        }
        Unit
    }

    @Test
    fun testProcessUnknownLanguage() = runBlocking {
        // process() returns error when config language is unknown
        assertFailsWith<Exception> {
            val config = MAPPER.readValue("{\"language\":\"nonexistent_xyz\"}", ProcessConfig::class.java)
            TreeSitterLanguagePack.process("x = 1", config)
        }
        Unit
    }

}
